(window.webpackJsonp=window.webpackJsonp||[]).push([[74],{624:function(v,_,p){"use strict";p.r(_);var t=p(2),e=Object(t.a)({},(function(){var v=this,_=v._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":v.$parent.slotKey}},[_("ul",[_("li",[_("p",[v._v("英语："),_("code",[v._v("单词只买一本背到考研前，或者用墨墨app背单词。真题只买一份历年真题，或者只买15-21考研真相，其余的打印手译本来做，间隔宽方便做笔记。完型新题型翻译通通不要买，就用真题或者手译本，网上有别人总结好的听课笔记，看不明白的再去听对应的课，课的资源也有免费分享的。作文也不买书，听潘赟刘晓燕网课以及网上总结各类作文笔记，总结自己的模板，可以分为消极现象和个人品质两类，多积累万能句。单词重中之重基础中基础，一定要一直背到考试。阅读是大头，看看陈仲凯和唐迟你更适应哪个老师就听哪个老师。二、英语：单词只买一本背到考研前，或者用墨墨app背单词。真题只买一份历年真题，或者只买15-21考研真相，其余的打印手译本来做，间隔宽方便做笔记。完型新题型翻译通通不要买，就用真题或者手译本，网上有别人总结好的听课笔记，看不明白的再去听对应的课，课的资源也有免费分享的。作文也不买书，听潘赟刘晓燕网课以及网上总结各类作文笔记，总结自己的模板，可以分为消极现象和个人品质两类，多积累万能句。单词重中之重基础中基础，一定要一直背到考试。阅读是大头，看看陈仲凯和唐迟你更适应哪个老师就听哪个老师。")])])]),v._v(" "),_("li",[_("p",[v._v("专业课：如果是偏背的，先搜集真题，把真题知识点理出来，看看哪些知识点考频较高，把知识点分一下类，哪些容易考名词解释、选择、填空、判断、简答、论述之类的，选择的知识点就是你理解能选出来就好，填空就要精确的背，判断也是要理解，名词解释简答论述就把知识点细化成几个关键词，自己能用关键词连接表达出来。背书的话，先看看目录，知道书的大概框架。然后按章节复习，先把这一章仔细看看，不知道不懂的点想方设法搞明白。然后再把这一章做一个框架，一个有层次的框架，大标题小标题，最后细化到需要解释的部分，就用几个关键词表示，不用抄书抄解释，标个页码。然后整本书框架整理好了，就可以背框架了。不用逐字逐句，能大概说出来")])]),v._v(" "),_("li",[_("p",[v._v("选择学校：可以去研招网自己搜，专业库能搜到你这个专业都有什么学校招生。硕士目录能搜到你这个专业在指定地区都有哪些学校招生，招生计划考生科目都有，然后去学校官网找分数线和报录比，如果找不到就找初试复试名单一般有成绩，就可以知道分数线和报录比了。多翻翻官网，有可能在学校研究生官网或者学院官网。也可以浏览器搜你专业的院校排名，根据排名选几个中意学校去学校官网查相关信息——转载自某书")])])]),v._v(" "),_("p",[_("code",[v._v("腿姐，徐涛强化班，肖老师最新22年网课，石雷鹏作文，1000题PDF，腿姐思维导图，张宇数学，刘晓燕英语全程，然后直接私我吧，分享gei大家，因为我曾经也在这边遇到了帮助我的贵人[doge][doge][doge]希望爱心能一直传递下去")])]),v._v(" "),_("hr"),v._v(" "),_("p",[v._v("1.确定专业，本专业考研一般都比跨考相对更稳，临近专业跨和文理跨是不同的概念，千万慎重")]),v._v(" "),_("p",[v._v("2.确定学校，这个时候需要花费大量时间搜集信息，搜集的最好是是规章制度和录取名单统计以及经验贴，招多少考研生等，不要听网上说“xxx 学校难考”，这种信息没有意义，徒增焦虑，可以看“第四轮学科评估”、“软科”这些查看专业排名，量力而行")]),v._v(" "),_("p",[v._v("3.如果有的学校还会进一步分组招生，就需要通过知网/外网/学校官网等做好每个组导师方向的调研，分数段和招生人数也要做好调研，这时候也可以查一些非官方消息，综合考虑")]),v._v(" "),_("p",[v._v("4.如果初试报名已经确定了，那么初试结束之前就不要考虑太多复试的事，浪费时间，初试考得好对复试总成绩有很大的帮助\n没有发文没有竞赛没有拿奖不要紧，考研的学生大概率都是这个样子，没必要担心")]),v._v(" "),_("p",[v._v("很多人抱怨某某学校“本科歧视”，事实上，很少有导师上来先看你什么本科然后决定去留，反而是因为“本科越好，复试表现大概率也好”导致了本科歧视，只要自己能力和水平好，那么本科一般不是阻碍你冲击 top 大学的因素\n反过来，本科好也不代表你复试就稳了(我身边就有武汉大学本科考 211 被刷的)")]),v._v(" "),_("hr"),v._v(" "),_("p",[v._v("考研选择大于努力！！！考研选择大于努力！！！考研选择大于努力！！！[跪了]这个选择是“适合的选择，而不是更好的选择”。举个例子，很多人都说考研难，但你有多大锅就下多少饭，合理分配时间就不会觉得难了，很多人是目标选的太高，自己水平就那样，做能力范围之外的事。大学三年不学习，妄图几个月逆袭好学校的是少数人，不要有幸存者偏差！")]),v._v(" "),_("p",[v._v("b 站的环境太影响考研人了，很多人视频就是 xx 天上岸北大，xx 三本逆袭 985，总让人觉得上岸很容易，希望别和他们比，把自己掂量清楚。")]),v._v(" "),_("p",[v._v("理性规划！理性规划！理性规划！自己目标与水平差的有多远，调剂的时候难度就有多大。考研最能教会大家什么是机会成本，一个能力为 b 的人报了 A 档学校，调剂时连符合自己的 B 档学校都收不到，很可能直接去 D 档了。能力为 b 报 B 档稳稳上岸不香吗？")])])}),[],!1,null,null,null);_.default=e.exports}}]);